  1	import * as React from 'react';
  2	import { PipelineKind, PipelineRunKind, PipelineWithLatest } from '../../types';
  3	import {
  4	  Dropdown,
  5	  DropdownItem,
  6	  DropdownList,
  7	  MenuToggle,
  8	  MenuToggleElement,
  9	} from '@patternfly/react-core';
 10	import { EllipsisVIcon } from '@patternfly/react-icons';
 11	import {
 12	  KEBAB_ACTION_DELETE_ID,
 13	  KEBAB_ACTION_EDIT_ANNOTATIONS_ID,
 14	  KEBAB_ACTION_EDIT_ID,
 15	  KEBAB_ACTION_EDIT_LABELS_ID,
 16	  KEBAB_BUTTON_ID,
 17	  StartedByAnnotation,
 18	} from '../../consts';
 19	import { useTranslation } from 'react-i18next';
 20	import {
 21	  k8sCreate,
 22	  useAccessReview,
 23	  useAnnotationsModal,
 24	  useDeleteModal,
 25	  useLabelsModal,
 26	  useModal,
 27	} from '@openshift-console/dynamic-plugin-sdk';
 28	import { PipelineModel, PipelineRunModel } from '../../models';
 29	import _ from 'lodash';
 30	import {
 31	  AddTriggerModal,
 32	  RemoveTriggerModal,
 33	  startPipelineModal,
 34	} from '../start-pipeline';
 35	import { useNavigate } from 'react-router-dom-v5-compat';
 36	import { errorModal } from '../modals/error-modal';
 37	import { getPipelineRunData } from '../utils/utils';
 38	import { getReferenceForModel } from '../pipelines-overview/utils';
 39	import { rerunPipeline } from '../utils/pipelines-actions';
 40	import { usePipelineTriggerTemplateNames } from '../utils/triggers';
 41	import { resourcePathFromModel } from '../utils/utils';
 42	
 43	type PipelineKebabProps = {
 44	  pipeline: PipelineWithLatest;
 45	  currentUser: string;
 46	};
 47	
 48	export const triggerPipeline = (
 49	  pipeline: PipelineKind,
 50	  currentUser: string,
 51	  onSubmit?: (pipelineRun: PipelineRunKind) => void,
 52	) => {
 53	  k8sCreate({
 54	    model: PipelineRunModel,
 55	    data: getPipelineRunData(pipeline, currentUser),
 56	  })
 57	    .then(onSubmit)
 58	    .catch((err) => errorModal({ error: err.message }));
 59	};
 60	
 61	const PipelineKebab: React.FC<PipelineKebabProps> = ({
 62	  pipeline,
 63	  currentUser,
 64	}) => {
 65	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 66	  const { name, namespace } = pipeline.metadata;
 67	  const launchDeleteModal = useDeleteModal(pipeline);
 68	  const launchAnnotationsModal = useAnnotationsModal(pipeline);
 69	  const launchLabelsModal = useLabelsModal(pipeline);
 70	  const launchModal = useModal();
 71	  const navigate = useNavigate();
 72	  const [isOpen, setIsOpen] = React.useState(false);
 73	  const templateNames = usePipelineTriggerTemplateNames(name, namespace) || [];
 74	  const onToggle = () => {
 75	    setIsOpen(!isOpen);
 76	  };
 77	
 78	  const onSelect = () => {
 79	    setIsOpen(false);
 80	  };
 81	
 82	  const [canCreateResource] = useAccessReview({
 83	    group: PipelineRunModel.apiGroup,
 84	    resource: PipelineRunModel.plural,
 85	    verb: 'create',
 86	    name,
 87	    namespace,
 88	  });
 89	
 90	  const [canEditResource] = useAccessReview({
 91	    group: PipelineModel.apiGroup,
 92	    resource: PipelineModel.plural,
 93	    verb: 'update',
 94	    name,
 95	    namespace,
 96	  });
 97	
 98	  const [canDeleteResource] = useAccessReview({
 99	    group: PipelineModel.apiGroup,
100	    resource: PipelineModel.plural,
101	    verb: 'delete',
102	    name,
103	    namespace,
104	  });
105	
106	  const handlePipelineRunSubmit = (pipelineRun: PipelineRunKind) => {
107	    navigate(
108	      resourcePathFromModel(
109	        PipelineRunModel,
110	        pipelineRun.metadata.name,
111	        pipelineRun.metadata.namespace,
112	      ),
113	    );
114	  };
115	
116	  const startPipeline = () => {
117	    const params = _.get(pipeline, ['spec', 'params'], []);
118	    const resources = _.get(pipeline, ['spec', 'resources'], []);
119	    const workspaces = _.get(pipeline, ['spec', 'workspaces'], []);
120	
121	    if (!_.isEmpty(params) || !_.isEmpty(resources) || !_.isEmpty(workspaces)) {
122	      launchModal(startPipelineModal, {
123	        pipeline,
124	        onSubmit: handlePipelineRunSubmit,
125	      });
126	    } else {
127	      triggerPipeline(pipeline, currentUser, handlePipelineRunSubmit);
128	    }
129	  };
130	
131	  const rerunPipelineAndRedirect = () => {
132	    rerunPipeline(
133	      PipelineRunModel,
134	      pipeline.latestRun,
135	      currentUser,
136	      launchModal,
137	      {
138	        onComplete: handlePipelineRunSubmit,
139	      },
140	    );
141	  };
142	
143	  const addTrigger = () => {
144	    const cleanPipeline: PipelineKind = {
145	      ...pipeline,
146	      metadata: {
147	        ...pipeline.metadata,
148	        annotations: _.omit(pipeline.metadata.annotations, [
149	          StartedByAnnotation.user,
150	        ]),
151	      },
152	    };
153	    launchModal(AddTriggerModal, { pipeline: cleanPipeline });
154	  };
155	
156	  const removeTrigger = () => {
157	    launchModal(RemoveTriggerModal, { pipeline });
158	  };
159	
160	  const editURL = `/k8s/ns/${namespace}/${getReferenceForModel(
161	    PipelineModel,
162	  )}/${encodeURIComponent(name)}/builder`;
163	
164	  const dropdownItems = [
165	    <DropdownItem
166	      key="start-pipeline"
167	      component="button"
168	      isDisabled={!canCreateResource}
169	      data-test-action="start-pipeline"
170	      onClick={startPipeline}
171	    >
172	      {t('Start')}
173	    </DropdownItem>,
174	    ...(pipeline.latestRun
175	      ? [
176	          <DropdownItem
177	            key="start-last-run"
178	            component="button"
179	            isDisabled={!canCreateResource}
180	            data-test-action="start-last-run"
181	            onClick={rerunPipelineAndRedirect}
182	          >
183	            {t('Start last run')}
184	          </DropdownItem>,
185	        ]
186	      : []),
187	    <DropdownItem
188	      key="add-trigger"
189	      component="button"
190	      isDisabled={!canCreateResource}
191	      data-test-action="add-trigger"
192	      onClick={addTrigger}
193	    >
194	      {t('Add Trigger')}
195	    </DropdownItem>,
196	    ...(templateNames.length > 0
197	      ? [
198	          <DropdownItem
199	            key="remove-trigger"
200	            component="button"
201	            isDisabled={!canDeleteResource}
202	            data-test-action="remove-trigger"
203	            onClick={removeTrigger}
204	          >
205	            {t('Remove Trigger')}
206	          </DropdownItem>,
207	        ]
208	      : []),
209	    <DropdownItem
210	      key={KEBAB_ACTION_EDIT_LABELS_ID}
211	      component="button"
212	      onClick={launchLabelsModal}
213	      isDisabled={!canEditResource}
214	      data-test-action={KEBAB_ACTION_EDIT_LABELS_ID}
215	    >
216	      {t('Edit labels')}
217	    </DropdownItem>,
218	    <DropdownItem
219	      key={KEBAB_ACTION_EDIT_ANNOTATIONS_ID}
220	      component="button"
221	      onClick={() => launchAnnotationsModal()}
222	      isDisabled={!canEditResource}
223	      data-test-action={KEBAB_ACTION_EDIT_ANNOTATIONS_ID}
224	    >
225	      {t('Edit annotations')}
226	    </DropdownItem>,
227	    <DropdownItem
228	      key={KEBAB_ACTION_EDIT_ID}
229	      component="button"
230	      onClick={() => navigate(editURL)}
231	      isDisabled={!canEditResource}
232	      data-test-action={KEBAB_ACTION_EDIT_ID}
233	    >
234	      {t('Edit Pipeline')}
235	    </DropdownItem>,
236	    <DropdownItem
237	      key={KEBAB_ACTION_DELETE_ID}
238	      component="button"
239	      onClick={launchDeleteModal}
240	      isDisabled={!canDeleteResource}
241	      data-test-action={KEBAB_ACTION_DELETE_ID}
242	    >
243	      {t('Delete Pipeline')}
244	    </DropdownItem>,
245	  ];
246	  return (
247	    <Dropdown
248	      onSelect={onSelect}
249	      onOpenChange={(isOpen: boolean) => setIsOpen(isOpen)}
250	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
251	        <MenuToggle
252	          ref={toggleRef}
253	          aria-label="kebab menu"
254	          variant="plain"
255	          onClick={onToggle}
256	          isExpanded={isOpen}
257	          id={KEBAB_BUTTON_ID}
258	          data-test={KEBAB_BUTTON_ID}
259	        >
260	          <EllipsisVIcon />
261	        </MenuToggle>
262	      )}
263	      isOpen={isOpen}
264	      isPlain={false}
265	      popperProps={{ position: 'right' }}
266	    >
267	      <DropdownList>{dropdownItems}</DropdownList>
268	    </Dropdown>
269	  );
270	};
271	
272	export default PipelineKebab;

